#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.exportLogFiles)]
    public class ExportLogFilesOptionButton : OptionButtonDefinition
    {
        public ExportLogFilesOptionButton(string nsp, string name) : base(nsp, name)
        {
        }
        public override void OnClick()
        {
            Global.Debugs.ExportLogFiles();
        }
    }
}
